//! AeonFlow 10-byte header + payload — wire-compatible with `open-source/aeon/src/flow/FlowCodec.ts`.
//!
//! Layout (big-endian for multi-byte fields, matching `DataView` defaults in JS):
//! - [0..2]   stream_id u16
//! - [2..6]   sequence u32
//! - [6]      flags u8
//! - [7..10]  payload length u24

pub const HEADER_SIZE: usize = 10;
pub const MAX_PAYLOAD_LEN: usize = 0xFF_FFFF;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct FlowFrame {
    pub stream_id: u16,
    pub sequence: u32,
    pub flags: u8,
    pub payload: Vec<u8>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum FrameError {
    TruncatedHeader,
    TruncatedPayload { need: usize, have: usize },
    PayloadTooLong(usize),
}

impl std::fmt::Display for FrameError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            FrameError::TruncatedHeader => write!(f, "buffer too small for header"),
            FrameError::TruncatedPayload { need, have } => {
                write!(f, "buffer too small for payload: need {need}, have {have}")
            }
            FrameError::PayloadTooLong(n) => write!(f, "payload length {n} exceeds maximum"),
        }
    }
}

impl std::error::Error for FrameError {}

/// Encode one frame: `HEADER_SIZE` + payload.
pub fn encode_frame(frame: &FlowFrame) -> Result<Vec<u8>, FrameError> {
    let plen = frame.payload.len();
    if plen > MAX_PAYLOAD_LEN {
        return Err(FrameError::PayloadTooLong(plen));
    }
    let mut out = Vec::with_capacity(HEADER_SIZE + plen);
    out.extend_from_slice(&frame.stream_id.to_be_bytes());
    out.extend_from_slice(&frame.sequence.to_be_bytes());
    out.push(frame.flags);
    out.push(((plen >> 16) & 0xff) as u8);
    out.push(((plen >> 8) & 0xff) as u8);
    out.push((plen & 0xff) as u8);
    out.extend_from_slice(&frame.payload);
    Ok(out)
}

/// Decode one frame from `buf` at `off`. Returns `(frame, bytes_consumed)`.
pub fn decode_frame(buf: &[u8], off: usize) -> Result<(FlowFrame, usize), FrameError> {
    if buf.len().saturating_sub(off) < HEADER_SIZE {
        return Err(FrameError::TruncatedHeader);
    }
    let o = off;
    let stream_id = u16::from_be_bytes([buf[o], buf[o + 1]]);
    let sequence = u32::from_be_bytes([buf[o + 2], buf[o + 3], buf[o + 4], buf[o + 5]]);
    let flags = buf[o + 6];
    let len = ((buf[o + 7] as usize) << 16) | ((buf[o + 8] as usize) << 8) | (buf[o + 9] as usize);
    if len > MAX_PAYLOAD_LEN {
        return Err(FrameError::PayloadTooLong(len));
    }
    if buf.len().saturating_sub(o + HEADER_SIZE) < len {
        return Err(FrameError::TruncatedPayload {
            need: len,
            have: buf.len().saturating_sub(o + HEADER_SIZE),
        });
    }
    let payload = buf[o + HEADER_SIZE..o + HEADER_SIZE + len].to_vec();
    let frame = FlowFrame {
        stream_id,
        sequence,
        flags,
        payload,
    };
    Ok((frame, HEADER_SIZE + len))
}

/// Scan concatenated frames (same layout as `FlowCodec.decodeBatch`).
pub fn decode_all(buf: &[u8]) -> Result<Vec<FlowFrame>, FrameError> {
    let mut out = Vec::new();
    let mut i = 0usize;
    while i < buf.len() {
        let (f, n) = decode_frame(buf, i)?;
        i += n;
        out.push(f);
    }
    Ok(out)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn encode_decode_roundtrip_matches_flowcodec_layout() {
        let f = FlowFrame {
            stream_id: 1,
            sequence: 2,
            flags: 3,
            payload: b"hello".to_vec(),
        };
        let enc = encode_frame(&f).unwrap();
        assert_eq!(
            enc,
            vec![0, 1, 0, 0, 0, 2, 3, 0, 0, 5, b'h', b'e', b'l', b'l', b'o']
        );
        let (d, n) = decode_frame(&enc, 0).unwrap();
        assert_eq!(n, enc.len());
        assert_eq!(d, f);
    }
}
